import { Component, createEffect, createSignal, For, onCleanup, Show } from 'solid-js';
import { cn } from '@utils/cn';
import { ZIndex, ZIndexType } from '@components/z-index';
import { contextMenuStore } from './context-menu.store';
import type { ContextMenuProps, RenderedItem } from './context-menu.types';
import ChevronRight from 'lucide-solid/icons/chevron-right';

type MenuItemProps = {
  item: RenderedItem;
  close: () => void;
  customClass?: Partial<Record<'item' | 'separator' | 'submenu', string>>;
};

const MenuItem: Component<MenuItemProps> = props => {
  if (props.item.type === 'separator') {
    return <div class={cn('cm03', props.customClass?.separator)} />;
  }

  if (props.item.type === 'submenu') {
    const item = props.item;
    let submenuRef!: HTMLDivElement;
    const [flip, setFlip] = createSignal(false);

    createEffect(function detectSubmenuEdge() {
      const rafId = requestAnimationFrame(function checkEdge() {
        if (!submenuRef) return;
        const rect = submenuRef.getBoundingClientRect();
        if (rect.right > window.innerWidth) setFlip(true);
        else setFlip(false);
      });
      onCleanup(() => cancelAnimationFrame(rafId));
    });

    return (
      <div
        class={cn('cm04', item.disabled && 'cm04--disabled', props.customClass?.submenu)}
        aria-disabled={item.disabled}
      >
        <div class="cm05">
          <Show when={item.prefixIcon}>
            <span class="cm06">{item.prefixIcon}</span>
          </Show>
          <span class="cm07">{item.label}</span>
          <span class="cm08">
            <ChevronRight size={14} />
          </span>
        </div>
        <div ref={el => (submenuRef = el)} class={cn('cm09', flip() && 'cm09--flip')}>
          <For each={item.items}>
            {sub => <MenuItem item={sub} close={props.close} customClass={props.customClass} />}
          </For>
        </div>
      </div>
    );
  }

  const item = props.item;
  return (
    <button
      type="button"
      class={cn('cm02', item.disabled && 'cm02--disabled', props.customClass?.item)}
      disabled={item.disabled}
      onClick={() => {
        if (item.disabled) return;
        item.onClick();
        props.close();
      }}
    >
      <Show when={item.prefixIcon}>
        <span class="cm06">{item.prefixIcon}</span>
      </Show>
      <span class="cm07">{item.label}</span>
      <Show when={item.shortcut}>
        <span class="cm10">{item.shortcut}</span>
      </Show>
    </button>
  );
};

type MenuContentProps = {
  x: number;
  y: number;
  items: RenderedItem[];
  close: () => void;
  customClass?: Partial<Record<'content' | 'item' | 'separator' | 'submenu', string>>;
};

const MenuContent: Component<MenuContentProps> = props => {
  let panelRef!: HTMLDivElement;
  const [style, setStyle] = createSignal({ left: `${props.x}px`, top: `${props.y}px` });

  createEffect(function adjustPosition() {
    const rafId = requestAnimationFrame(function computePosition() {
      if (!panelRef) return;
      const rect = panelRef.getBoundingClientRect();
      const vw = window.innerWidth;
      const vh = window.innerHeight;

      const left = rect.right > vw ? Math.max(0, props.x - rect.width) : props.x;
      const top = rect.bottom > vh ? Math.max(0, props.y - rect.height) : props.y;

      setStyle({ left: `${left}px`, top: `${top}px` });
    });
    onCleanup(() => cancelAnimationFrame(rafId));
  });

  return (
    <div
      ref={el => (panelRef = el)}
      class={cn('cm01', props.customClass?.content)}
      style={style()}
      onContextMenu={e => e.preventDefault()}
    >
      <For each={props.items}>
        {item => <MenuItem item={item} close={props.close} customClass={props.customClass} />}
      </For>
    </div>
  );
};

export const ContextMenu: Component<ContextMenuProps> = props => {
  const state = () => contextMenuStore.menuState();
  const close = () => contextMenuStore.close();

  createEffect(function registerGlobalListeners() {
    if (!state()) return;

    function onMouseDown(e: MouseEvent) {
      const target = e.target as Element;
      if (!target.closest('.cm01')) close();
    }

    function onKeyDown(e: KeyboardEvent) {
      if (e.key === 'Escape') close();
    }

    document.addEventListener('mousedown', onMouseDown);
    document.addEventListener('keydown', onKeyDown);

    onCleanup(function removeGlobalListeners() {
      document.removeEventListener('mousedown', onMouseDown);
      document.removeEventListener('keydown', onKeyDown);
    });
  });

  return (
    <ZIndex open={!!state()} type={ZIndexType.DROPDOWN} class="inset-0">
      <Show when={state()}>
        {s => (
          <MenuContent
            x={s().x}
            y={s().y}
            items={s().items}
            close={close}
            customClass={props.class}
          />
        )}
      </Show>
    </ZIndex>
  );
};
